import com.amazonaws.auth.{AWSCredentialsProvider, DefaultAWSCredentialsProviderChain}
import com.amazonaws.services.s3.AmazonS3
import com.amazonaws.services.s3.AmazonS3ClientBuilder
import scala.util.Try

class AwsService {

  private def createS3Client(): AmazonS3 = {
    AmazonS3ClientBuilder.standard()
      .withCredentials(getCredentialsProvider)
      .withRegion("us-east-1") // Change to your desired region
      .build()
  }

  private def getCredentialsProvider: AWSCredentialsProvider = {
    new DefaultAWSCredentialsProviderChain()
  }

  def uploadFile(bucketName: String, key: String, filePath: String): Try[Unit] = {
    Try {
      val s3Client = createS3Client()
      val file = new java.io.File(filePath)
      s3Client.putObject(bucketName, key, file)
    }
  }

  def listFiles(bucketName: String): Try[List[String]] = {
    Try {
      val s3Client = createS3Client()
      val objects = s3Client.listObjects(bucketName).getObjectSummaries
      objects.asScala.map(_.getKey).toList
    }
  }
}